diff --git a/CMakeLists.txt b/CMakeLists.txt
new file mode 100644
index 0000000..d4383f9
--- /dev/null
+++ b/CMakeLists.txt
@@ -0,0 +1,58 @@
+cmake_minimum_required(VERSION 2.8.12 FATAL_ERROR)
+
+# MakeLists, adapted from Detectron https://github.com/facebookresearch/Detectron/blob/master
+
+# Find the Caffe2 package.
+# Caffe2 exports the required targets, so find_package should work for
+# the standard Caffe2 installation. If you encounter problems with finding
+# the Caffe2 package, make sure you have run `make install` when installing
+# Caffe2 (`make install` populates your share/cmake/Caffe2).
+find_package(Caffe2 REQUIRED)
+
+if (${CAFFE2_VERSION} VERSION_LESS 0.8.2)
+  # Pre-0.8.2 caffe2 does not have proper interface libraries set up, so we
+  # will rely on the old path.
+  message(WARNING
+      "You are using an older version of Caffe2 (version " ${CAFFE2_VERSION}
+      "). Please consider moving to a newer version.")
+  include(cmake/legacy/legacymake.cmake)
+  return()
+endif()
+
+# Add compiler flags.
+set(CMAKE_C_FLAGS "${CMAKE_C_FLAGS} -std=c11")
+set(CMAKE_CXX_FLAGS "${CMAKE_CXX_FLAGS} -std=c++14 -O2 -fPIC -Wno-narrowing")
+
+# Print configuration summary.
+include(cmake/Summary.cmake)
+vmz_print_config_summary()
+
+# Collect AV ops sources.
+file(GLOB CUSTOM_OPS_CPU_SRCS ${CMAKE_CURRENT_SOURCE_DIR}/ops/av_input_op.cc)
+file(GLOB CUSTOM_OPS_GPU_SRCS ${CMAKE_CURRENT_SOURCE_DIR}/ops/av_input_op_gpu.cc)
+
+# Install custom CPU ops lib.
+add_library(
+    caffe2_av_input_ops SHARED
+    ${CUSTOM_OPS_CPU_SRCS})
+
+target_include_directories(
+    caffe2_av_input_ops PRIVATE
+    ${CAFFE2_INCLUDE_DIRS})
+
+target_link_libraries(caffe2_av_input_ops caffe2_library)
+install(TARGETS caffe2_av_input_ops DESTINATION lib)
+
+# Install custom GPU ops lib, if gpu is present.
+if (CAFFE2_USE_CUDA OR CAFFE2_FOUND_CUDA)
+  # Additional -I prefix is required for CMake versions before commit (< 3.7):
+  # https://github.com/Kitware/CMake/commit/7ded655f7ba82ea72a82d0555449f2df5ef38594
+  list(APPEND CUDA_INCLUDE_DIRS -I${CAFFE2_INCLUDE_DIRS})
+  CUDA_ADD_LIBRARY(
+      caffe2_av_input_ops_gpu SHARED
+      ${CUSTOM_OPS_CPU_SRCS}
+      ${CUSTOM_OPS_GPU_SRCS})
+
+  target_link_libraries(caffe2_av_input_ops_gpu caffe2_gpu_library)
+  install(TARGETS caffe2_av_input_ops_gpu DESTINATION lib)
+endif()
