+
+
+class LogSpectrum {
+ public:
+  LogSpectrum(
+      int numChannels,
+      float samplingRate,
+      int windowLength,
+      int windowStep,
+      float startFreq = 0,
+      float endFreq = -1,
+      bool normalized = true);
+
+  ~LogSpectrum();
+
+  void Cleanup();
+
+  bool Init();
+
+  int Write(float* first, size_t numSamples);
+
+  int Read(float* feat);
+
+ private:
+  void Apply(float* feat);
+
+  void PowerSpectrum();
+
+  int numChannels_;
+  float samplingRate_;
+  int windowLength_;
+  int windowStep_;
+  int fftSize_;
+  float startFreq_;
+  float endFreq_;
+  bool normalized_;
+
+  int filterLength_;
+  float* filters_;
+  double* featFrame_;
